import scala.collection.mutable
import scala.collection.mutable.PriorityQueue

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
    val n = online.length
    val adj = mutable.Map[Int, mutable.ListBuffer[(Int, Long)]]().withDefaultValue(mutable.ListBuffer.empty)
    for (e <- edges) {
        val u = e(0).toInt
        val v = e(1).toInt
        val cost = e(2)
        adj(u) += ((v, cost))
    }

    case class State(minCost: Long, totalCost: Long, node: Int)
    implicit val ord: Ordering[State] = Ordering.by(-_.minCost)
    val maxHeap = mutable.PriorityQueue[State]()

    maxHeap.enqueue(State(Long.MaxValue, 0L, 0))
    var maxScore = -1L

    while (maxHeap.nonEmpty) {
        val current = maxHeap.dequeue()
        val currentMinCost = current.minCost
        val totalCost = current.totalCost
        val u = current.node

        if (u == n - 1) {
            if (totalCost <= k) {
                maxScore = math.max(maxScore, currentMinCost)
            }
        } else {
            for ((v, cost) <- adj(u)) {
                if (online(v) || v == n - 1) {
                    val newTotal = totalCost + cost
                    if (newTotal <= k) {
                        val newMin = math.min(currentMinCost, cost)
                        maxHeap.enqueue(State(newMin, newTotal, v))
                    }
                }
            }
        }
    }

    if (maxScore == Long.MaxValue) -1 else maxScore
}
